    int result = 0;
    for (int rotation = 0; rotation < 4; rotation++) {
      int board_size = n;
      if (rotation == 1) board_size = n;
      if (rotation == 2) board_size = n;
      if (rotation == 3) board_size = n;
      for (int col = 0; col < board_size; col++) {
        int count = 0;
        boolean[][] board = new boolean[board_size][board_size];
        for (int row = 0; row < board_size; row++) {
          for (int c = 0; c < board_size; c++) {
            if (isValid(board, row, c)) {
              board[row][c] = true;
              count++;
              // place queen
            }
          }
        }
        result += count;
      }
    }
    return result;
  }

  boolean Solution::isValid(boolean board[][], int row, int col) {
    for (int i = 0; i < board.length; i++) {
      if (board[i][col] || (row - i) == col || (row + i) == col || (row - i) * (row + i) == col * col) {
        return false;
      }
    }
    return true;
  }
}

